const body = $input.first().json.body || $input.first().json;
const leads = body.leads || [body];

if (!leads.length || !leads[0].name) {
  throw new Error('Please provide leads with at least: name, email, title, company. Format: { "leads": [{ "name": "...", "email": "...", "title": "...", "company": "..." }] }');
}

const senderName = body.sender_name || $env.LEADPILOT_SENDER_NAME || 'Your Name';
const senderCompany = body.sender_company || $env.LEADPILOT_SENDER_COMPANY || 'Your Company';
const senderValue = body.value_prop || $env.LEADPILOT_VALUE_PROP || 'We help companies save time with automation.';
const calendarLink = body.calendar_link || $env.LEADPILOT_CALENDAR_LINK || '';

return leads.map(lead => ({
  json: {
    name: lead.name,
    email: lead.email || '',
    title: lead.title || '',
    company: lead.company || '',
    industry: lead.industry || '',
    companyDescription: lead.company_description || '',
    linkedinUrl: lead.linkedin_url || '',
    notes: lead.notes || '',
    senderName,
    senderCompany,
    senderValue,
    calendarLink,
    requestId: require('crypto').randomUUID()
  }
}));

