const lead = $('Parse Lead List').item;
const emailRaw = $input.first().json;
let emailData;
try {
  emailData = JSON.parse(emailRaw.message?.content || emailRaw.content || '{}');
} catch (e) {
  throw new Error('Failed to parse email: ' + e.message);
}

return [{
  json: {
    ...lead.json,
    email_subject: emailData.subjectLine || '',
    email_body: emailData.emailBody || '',
    followUp_subject: emailData.followUp?.subject || '',
    followUp_body: emailData.followUp?.body || '',
    generatedAt: new Date().toISOString()
  }
}];
